INSERT INTO materials (id, module_id, content_text, video_url, material_order) VALUES 
-- ==========================================
-- MATERI DATA ANALYST
-- ==========================================
-- Minggu 1
('mat-d1-1', 'md-data-1', 'Video 1: Pengenalan Roadmap & Pola Pikir Analis Data. [span_2](start_span)Pengertian: Video panduan konseptual yang merangkum keseluruhan jalur belajar.[span_2](end_span) [span_3](start_span)Fungsi: Memberikan struktur silabus belajar yang jelas agar proses belajar terarah dari statistik, Excel, SQL, hingga Python.[span_3](end_span) [span_4](start_span)Cara Penggunaan: Video ini tidak berisi coding, melainkan digunakan sebagai peta penunjuk arah.[span_4](end_span) [span_5](start_span)Penjelasan & Timestamp: Penjelasan kerangka skill utama yang wajib dikuasai untuk pasar kerja analitik saat ini.[span_5](end_span) Pentingnya memahami statistik dasar (seperti mean, median, probabilitas) sebelum menyentuh data. [span_6](start_span)Alasan mengapa fungsi-fungsi Excel sangat krusial untuk level pemula.[span_6](end_span) [span_7](start_span)Pembahasan SQL sebagai bahasa yang paling absolut dan tidak bisa dinegosiasikan di dunia data.[span_7](end_span)', 'http://www.youtube.com/watch?v=gGzTVW5WHMU', 1),
('mat-d1-2', 'md-data-1', 'Video 2: Excel Fundamental & Fungsi Esensial. Pengertian: Pengenalan operasi spreadsheet untuk kalkulasi mentah.[span_8](end_span) [span_9](start_span)Fungsi: Mengoperasikan tabulasi harian, pembersihan spasi, dan fungsi hitung matematis.[span_9](end_span) [span_10](start_span)Cara Penggunaan (Formula): Menggunakan fungsi bawaan langsung pada sel, seperti perhitungan matematika logika dasar =A1+B1 atau agregasi =AVERAGE(range).[span_10](end_span)', 'http://www.youtube.com/watch?v=pCJ15nGFgVg', 2),
('mat-d1-3', 'md-data-1', 'Video 3: Pembersihan Data & Pembuatan Dashboard Excel. Pengertian: Teknik pemrosesan data lanjutan untuk merapikan kumpulan data kotor (raw data)[span_11](start_span). Fungsi: Mengotomatiskan pencarian antar tabel, memberikan label logika, dan meringkas jutaan baris menjadi Pivot visual.[span_11](end_span) Cara Coding / Formula: Mencari data: =VLOOKUP(lookup_value, table_array, col_index_num, 0). Kondisi logika: =IF(C2>=50, "Bonus", "No Bonus"). [span_12](start_span)Penjelasan & Timestamp: Menggunakan fitur "Text to Columns" untuk memecah data teks yang bergabung menjadi beberapa kolom rapi.[span_12](end_span) Penerapan rumus logika IF bersyarat. [span_13](start_span)Penjelasan mendalam cara memanggil data dari tabel lain menggunakan VLOOKUP.[span_13](end_span) [span_14](start_span)Menggunakan fitur Pivot Table untuk merangkum dan menyatukan kategori data dalam hitungan detik.[span_14](end_span)', 'http://www.youtube.com/watch?v=SA_SDo-cqpg', 3),

-- Minggu 2
('mat-d2-1', 'md-data-2', 'Video 4: Dasar SQL & Relational Database. Pengertian: Bahasa standar (Structured Query Language) [span_15](start_span)untuk berkomunikasi dengan sistem database.[span_15](end_span) Fungsi: Melakukan ekstraksi, manipulasi, serta penggabungan berbagai tabel data relasional secara cepat. [span_16](start_span)Cara Coding: Memilih kolom: SELECT nama_kolom FROM nama_tabel;[span_16](end_span) Menyaring data: WHERE kondisi = ''kriteria''; [span_17](start_span)Menggabungkan dua tabel: LEFT JOIN tabel_b ON tabel_a.id = tabel_b.id;[span_17](end_span) Penjelasan & Timestamp: Dasar mengeksekusi kueri SELECT dan FROM. [span_18](start_span)Menggunakan klausul WHERE untuk memfilter data spesifik.[span_18](end_span) [span_19](start_span)Penggunaan GROUP BY untuk menghitung agregasi seperti total atau nilai rata-rata dari suatu kelompok.[span_19](end_span) [span_20](start_span)Konsep LEFT JOIN untuk menggabungkan dua tabel informasi yang memiliki key yang sama.[span_20](end_span)', 'http://www.youtube.com/watch?v=7mz73uXD9DA', 1),
('mat-d2-2', 'md-data-2', 'Video 5: Manipulasi Data Lanjutan. Pengertian: Teknik operasi himpunan (set operations) [span_21](start_span)pada database.[span_21](end_span) [span_22](start_span)Fungsi: Mengolah dan membandingkan output dari kueri berbeda (seperti mencari irisan data atau menggabungkan baris).[span_22](end_span) Cara Coding: Irisan himpunan: Kueri A INTERSECT Kueri B; [span_23](start_span)Menghitung jumlah data spesifik: SELECT COUNT(kolom) FROM tabel;[span_23](end_span)', 'http://www.youtube.com/watch?v=OT1RErkfLNQ', 2),
('mat-d2-3', 'md-data-2', 'Video 6: Analisis Statistik dengan SQL. Pengertian: Analisis kompleks menggunakan konsep Window Functions.[span_24](end_span) [span_25](start_span)Fungsi: Menghitung matrik analitik seperti persentase kumulatif atau moving average dengan tetap mempertahankan baris data asli.[span_25](end_span) [span_26](start_span)Cara Coding: SUM(revenue) OVER(PARTITION BY department_id) untuk menghitung total berjalan per departemen.[span_26](end_span)', 'http://www.youtube.com/watch?v=SSKVgrwhzus', 3),

-- Minggu 3
('mat-d3-1', 'md-data-3', 'Video 7: Pengenalan Power BI & Transformasi Data. Pengertian: Perangkat lunak visualisasi (Business Intelligence) [span_27](start_span)untuk merancang dashboard.[span_27](end_span) [span_28](start_span)Fungsi: Menghubungkan sumber data mentah, mengubah tipe data, dan menyiapkan fondasi grafik bisnis.[span_28](end_span) [span_29](start_span)Cara Penggunaan: Mengimpor data melalui menu Get Data lalu membersihkannya di antarmuka Power Query Editor sebelum dimuat ke kanvas.[span_29](end_span)', 'http://www.youtube.com/watch?v=FwjaHCVNBWA', 1),
('mat-d3-2', 'md-data-3', 'Video 8: Data Modeling & Pengenalan DAX. Pengertian: DAX (Data Analysis Expressions) [span_30](start_span)adalah bahasa penulisan fungsi di dalam Power BI.[span_30](end_span) [span_31](start_span)Fungsi: Menciptakan metrik perhitungan baru (dinamakan Measures) yang bisa bereaksi dinamis sesuai filter yang diklik audiens.[span_31](end_span) [span_32](start_span)Cara Coding: Di dalam kolom formula DAX dituliskan: Profit Margin = DIVIDE(SUM(Sales [Profit]), SUM (Sales [Revenue])).[span_32](end_span)', 'http://www.youtube.com/watch?v=keDIUQCVhtA', 2),
('mat-d3-3', 'md-data-3', 'Video 9: UI/UX Dashboard Analytics. Pengertian: Desain antarmuka visualisasi yang berfokus pada kemudahan pembacaan data.[span_33](end_span) [span_34](start_span)Fungsi: Mengoptimalkan warna, tipografi, dan navigasi filter (slicers) agar informasi terlihat profesional dan user-friendly.[span_34](end_span) [span_35](start_span)Cara Penggunaan: Memanfaatkan panel Format Visual untuk menyetel ukuran font, warna elemen grafik, hingga pengaturan posisi dashboard yang proporsional.[span_35](end_span)', 'http://www.youtube.com/watch?v=uwe8C7K8fXY', 3),

-- Minggu 4
('mat-d4-1', 'md-data-4', 'Video 10: Persiapan Python & Pandas Dasar. Pengertian: Pandas adalah pustaka (library) [span_36](start_span)utama di Python untuk struktur data berbentuk tabel (DataFrame).[span_36](end_span) [span_37](start_span)Fungsi: Mengeksplorasi data, melihat anomali, serta mencari nilai yang hilang (missing values) secara sistematis.[span_37](end_span) Cara Coding: Membaca format csv: df = pd.read_csv(''nama_file.csv''). Melihat tipe data: df.dtypes. Mengecek kekosongan data: df.isna().sum(). [span_38](start_span)Penjelasan & Timestamp: Cara menggunakan library pandas untuk mengimpor dataset.[span_38](end_span) [span_39](start_span)Menggunakan perintah df.shape dan df.head() untuk menginspeksi dimensi kolom dan baris data awal.[span_39](end_span) [span_40](start_span)Cara menemukan jumlah data yang kosong/null di setiap kolom menggunakan isna().sum().[span_40](end_span) [span_41](start_span)Menggunakan fungsi value_counts() untuk menghitung distribusi atau frekuensi unik tiap kategori.[span_41](end_span) [span_42](start_span)Cara langsung membuat plot histogram untuk menganalisis penyebaran data kontinu.[span_42](end_span)', 'http://www.youtube.com/watch?v=xi0vhXFPegw', 1),
('mat-d4-2', 'md-data-4', 'Video 11: Analisis Lanjutan & Ekstraksi Insight. Pengertian: Pemanfaatan pustaka Seaborn dan Matplotlib dalam proses analisis eksplorasi.[span_43](end_span) [span_44](start_span)Fungsi: Mencari korelasi kuat antar variabel untuk mengambil kesimpulan (insight) bisnis melalui pendekatan visualisasi.[span_44](end_span) [span_45](start_span)Cara Coding: sns.scatterplot(x = ''harga'', y = ''penjualan'', data = df) untuk menemukan relasi antara metrik harga dan kuantitas.[span_45](end_span)', 'http://www.youtube.com/watch?v=9Zo5kVnY6Zs', 2),
('mat-d4-3', 'md-data-4', 'Video 12: Proyek Akhir Python & Cloud Integration. Pengertian: Menggabungkan skrip kode Python ke dalam satu proyek akhir portofolio.[span_46](end_span) [span_47](start_span)Fungsi: Melakukan analisis end-to-end yang mensimulasikan lingkungan kerja asli, di mana skrip dihubungkan pada layanan infrastruktur komputasi awan.[span_47](end_span) Cara Penggunaan: Menuliskan kode secara menyeluruh dan mengintegrasikannya (misalnya, via modul Boto3) ke layanan penyimpanan cloud seperti AWS (Amazon Web Services) untuk mengelola ketersediaan basis data dari server.', 'http://www.youtube.com/watch?v=3QoEFsbtU0c', 3),


-- ==========================================
-- MATERI WEB DEVELOPER
-- ==========================================
-- Week 1
('mat-w1-1', 'md-web-1', 'Video 1: Panduan Dasar Pembuatan Website (Dari Nol Hingga Publikasi)[span_48](start_span). Referensi: "Belajar Membuat WEBSITE Dari 0 Sampai Di PUBLISH" oleh Dea Afrizal. Materi ini dirancang sebagai fondasi awal untuk kurikulum course 30 hari.[span_48](end_span) [span_49](start_span)Pendekatannya berfokus langsung pada praktik tanpa bertele-tele pada teori rumit, sehingga sangat ideal untuk pemula.[span_49](end_span) Bagian 1: Pengertian & Konsep Dasar. [span_50](start_span)Pembuatan website pada dasarnya dibangun di atas dua pilar utama: - HTML: Ini adalah kerangka atau tulang punggung website.[span_50](end_span) [span_51](start_span)Fungsinya adalah untuk menstrukturkan dokumen, seperti membuat paragraf, menyisipkan gambar, membuat daftar isi, dan membagi halaman web ke dalam blok-blok spesifik.[span_51](end_span) - [span_52](start_span)CSS: Ini adalah alat rias atau kosmetik.[span_52](end_span) [span_53](start_span)CSS bertugas memodifikasi kerangka HTML tadi agar memiliki nilai estetika.[span_53](end_span) [span_54](start_span)Dengan CSS, kita bisa mengatur warna, ukuran huruf, tata letak, hingga animasi interaktif.[span_54](end_span) Bagian 2: Bedah Rumus (Kode) Utama. [span_55](start_span)A. Tag Struktur HTML: <html> ... </html>: Pembungkus utama.[span_55](end_span) Menandakan bahwa semua teks di dalamnya adalah kode web. [span_56](start_span)<head> ... </head>: Bagian "otak" yang tak terlihat di layar.[span_56](end_span) [span_57](start_span)Berisi informasi penting seperti <title> dan <link>.[span_57](end_span) <body> ... </body>: Bagian "tubuh". [span_58](start_span)Semua yang ada di dalam sini akan tampil di layar pengguna.[span_58](end_span) [span_59](start_span)B. Elemen Konten HTML: <div> ... </div>: Division (Kotak Kontainer).[span_59](end_span) [span_60](start_span)<ul> dan <li>: Unordered List dan List Item.[span_60](end_span) [span_61](start_span)<a href="..."> ... </a>: Anchor (Tautan/Link).[span_61](end_span) [span_62](start_span)<img>: Menampilkan gambar.[span_62](end_span) [span_63](start_span)<h1> hingga <h6>: Heading.[span_63](end_span) [span_64](start_span)C. Aturan CSS Kosmetik: { margin: 0;[span_64](end_span) padding: 0; [span_65](start_span)}: Rumus reset ajaib.[span_65](end_span) [span_66](start_span).nama-kelas { ... }: Tanda titik memanggil atribut class spesifik.[span_66](end_span) [span_67](start_span)100vh: Viewport Height.[span_67](end_span) D. CSS Flexbox & Animasi: display: flex; [span_68](start_span)Mengubah sifat kotak biasa menjadi fleksibel.[span_68](end_span) [span_69](start_span)Jika digabung dengan justify-content: center; dan align-items: center;, elemen akan otomatis berada persis di tengah layar.[span_69](end_span) [span_70](start_span):hover: Status bayangan.[span_70](end_span) transition: 0.5s; [span_71](start_span)Memberikan jeda transisi halus.[span_71](end_span) Bagian 3: Contoh Pengaplikasian (Praktik Langsung). 1. [span_72](start_span)Navbar: Menggunakan <div> yang diisi daftar menu <ul> dan <li>.[span_72](end_span) [span_73](start_span)CSS Flexbox digunakan untuk menjajarkan menu ini.[span_73](end_span) 2. [span_74](start_span)Content: Menggunakan <div> di tengah layar yang diisi logo YouTube dan dibungkus tag <a>.[span_74](end_span) 3. [span_75](start_span)Footer: Teks hak cipta sederhana menggunakan <h1>.[span_75](end_span) [span_76](start_span)Catatan Interaktivitas: Tombol-tombol navigasi di Navbar diberikan efek CSS :hover.[span_76](end_span) Bagian 4: Hasil Akhir & Publikasi (Deployment). [span_77](start_span)Proses tidak berhenti di komputer lokal.[span_77](end_span) [span_78](start_span)Materi ini mengajarkan cara meluncurkan hasil kode tersebut secara langsung ke internet: 1. Menggunakan hosting platform gratis bernama Replit.[span_78](end_span) 2. [span_79](start_span)Kode HTML dan CSS disalin ke dalam platform tersebut.[span_79](end_span) 3. [span_80](start_span)Hasilnya: Sistem seketika menghasilkan tautan URL publik yang live.[span_80](end_span) [span_81](start_span)Website tersebut sudah mengudara, bisa diklik, memuat navigasi antar-halaman yang berfungsi dengan baik.[span_81](end_span) [span_82](start_span)Kesimpulan: Rangkaian ini adalah contoh sempurna untuk modul pertama course yang cepat dan taktis.[span_82](end_span) [span_83](start_span)Mempelajari konsep, mengetik kode sederhana, dan langsung melihat hasilnya secara daring akan memberikan dorongan motivasi yang besar.[span_83](end_span)', 'https://youtu.be/71a2zeC71gk', 1),
('mat-w1-2', 'md-web-1', 'Video 2: Pengertian dan Fungsi Utama (HTML & CSS)[span_84](start_span). HTML: Diibaratkan sebagai tulang atau struktur.[span_84](end_span) [span_85](start_span)Jika disamakan dengan proses membangun rumah, HTML adalah tiang dan fondasinya.[span_85](end_span) [span_86](start_span)HTML berfungsi untuk membuat struktur dokumen, menyusun teks, dan meletakkan elemen di halaman website.[span_86](end_span) [span_87](start_span)CSS: Diibaratkan sebagai kulit atau kosmetik.[span_87](end_span) [span_88](start_span)CSS digunakan untuk menghiasi struktur yang sudah dibuat oleh HTML.[span_88](end_span) [span_89](start_span)Fungsinya untuk mewarnai dinding rumah, mengatur letak perabotan, mengatur font teks, hingga memberikan warna latar belakang.[span_89](end_span) [span_90](start_span)Kombinasi keduanya akan menghasilkan sebuah website statis.[span_90](end_span) [span_91](start_span)Persiapan Awal (Tools): Text Editor (Visual Studio Code).[span_91](end_span) [span_92](start_span)Web Browser (Google Chrome): Bertugas sebagai penerjemah yang akan membaca file kode tadi.[span_92](end_span) [span_93](start_span)Struktur Dasar dan Contoh HTML: File HTML harus disimpan dengan akhiran .html.[span_93](end_span) [span_94](start_span)Sebuah tag HTML memiliki rumus penulisan yang diapit oleh tanda kurung siku pembuka dan penutup.[span_94](end_span) [span_95](start_span)<!DOCTYPE html>: Menginformasikan kepada browser bahwa dokumen menggunakan HTML5.[span_95](end_span) <html>: Tag pembungkus keseluruhan elemen web. [span_96](start_span)<head>: Bagian kepala.[span_96](end_span) <body>: Bagian badan. [span_97](start_span)Segala sesuatu yang ada di dalam body inilah yang akan terlihat di layar.[span_97](end_span) [span_98](start_span)<h1> sampai <h6>: Heading.[span_98](end_span) [span_99](start_span)<a href="...">: Elemen Anchor.[span_99](end_span) <img src="...">: Menampilkan gambar. [span_100](start_span)Struktur Dasar dan Contoh CSS: Penulisan CSS terdiri dari tiga elemen dasar: Selector, Property, dan Value.[span_100](end_span) [span_101](start_span)Dalam video, diajarkan cara menulis CSS secara Internal atau External.[span_101](end_span) [span_102](start_span)Penjelasan Gaya CSS Tambahan (Box Model): Margin: Jarak dari luar kotak elemen.[span_102](end_span) [span_103](start_span)Border: Garis batas luar sebuah elemen.[span_103](end_span) [span_104](start_span)Padding: Jarak dari dalam kotak elemen.[span_104](end_span) [span_105](start_span)Formulir & Interaksi Lanjutan: Video ini juga mencontohkan bagaimana membuat Form atau area input.[span_105](end_span) Ringkasan: Video ini adalah fondasi yang sangat kuat karena membedah HTML dan CSS dari analogi dan live coding yang terstruktur. [span_106](start_span)Penonton diajarkan siklus developer yang sebenarnya: menulis perintah di Text Editor, menyimpan file, lalu me-refresh hasilnya di Web Browser.[span_106](end_span)', 'https://www.youtube.com/watch?v=3U1AhjEf7DM', 2),

-- Week 2
('mat-w2-1', 'md-web-2', 'Video 3: TUTORIAL JAVASCRIPT DASAR BAHASA INDONESIA. Video berdurasi sekitar 8 jam ini dirancang khusus untuk pemula yang ingin memahami fondasi JavaScript dari nol hingga siap memasuki tingkat lanjutan.[span_107](end_span) 1. [span_108](start_span)Pengertian dan Sejarah JavaScript: JavaScript adalah bahasa pemrograman jenis scripting yang berjalan di sisi klien.[span_108](end_span) [span_109](start_span)Berbeda dengan HTML (kerangka) dan CSS (kosmetik), JavaScript berfungsi untuk memberikan interaktivitas dan logika pada sebuah halaman web.[span_109](end_span) [span_110](start_span)Sejarah Singkat: Dibuat pada tahun 1995 oleh Brendan Eich.[span_110](end_span) [span_111](start_span)Tujuannya adalah membuat web lebih dinamis.[span_111](end_span) [span_112](start_span)Mitos Umum: JavaScript TIDAK SAMA dengan Java.[span_112](end_span) 2. [span_113](start_span)Fungsi JavaScript: Interaktivitas Front-End: Merespons klik tombol, animasi, validasi form.[span_113](end_span) [span_114](start_span)Full-Stack Development: JavaScript yang dulunya hanya berjalan di browser kini juga bisa digunakan untuk membuat sistem Back-End di dalam server (Node.js).[span_114](end_span) 3. [span_115](start_span)Persiapan: Web Browser dan Text Editor.[span_115](end_span) 4. [span_116](start_span)Konsep Dasar: Cara Menulis JavaScript (Embedded vs External).[span_116](end_span) [span_117](start_span)Variabel: let & const menggantikan var.[span_117](end_span) [span_118](start_span)let datanya bisa diubah, const mutlak.[span_118](end_span) [span_119](start_span)Tipe Data: Number, String, Boolean.[span_119](end_span) [span_120](start_span)Operasi Logika (If-Else) untuk mengambil keputusan.[span_120](end_span) [span_121](start_span)Perulangan (Looping) untuk menjalankan kode berkali-kali.[span_121](end_span) [span_122](start_span)Array & Object: Array adalah kumpulan data berurutan, Object menggunakan pasangan key-value.[span_122](end_span) [span_123](start_span)Function: Blok kode program yang bisa dipanggil berkali-kali.[span_123](end_span) [span_124](start_span)Fitur Modern: Arrow Function, Destructuring, Optional Chaining.[span_124](end_span) 5. [span_125](start_span)Debugging: Melacak masalah menggunakan kata kunci debugger; agar aplikasi pause sementara.[span_125](end_span) [span_126](start_span)Kesimpulan: Sangat sempurna sebagai materi inti silabus JavaScript untuk pemula, mulai dari penulisan variabel hingga proses pencarian masalah.[span_126](end_span)', 'https://youtu.be/SDROba_M42g', 1),

-- Week 3
('mat-w3-1', 'md-web-3', 'Video 4: Jago Git Dalam 2 Jam. 1. Pengertian Git: Git adalah sistem Version Control.[span_127](end_span) [span_128](start_span)Git akan merekam setiap perubahan yang dilakukan pada file, memberikan identitas (Hash), dan menyimpan riwayat secara terstruktur.[span_128](end_span) [span_129](start_span)Git adalah software open-source lokal, sedangkan GitHub adalah layanan cloud.[span_129](end_span) 2. [span_130](start_span)Fungsi Git: Backup Aman (History Tracking) untuk mundur (rollback) ke versi sebelumnya.[span_130](end_span) [span_131](start_span)Kolaborasi Tim tanpa saling menimpa kode.[span_131](end_span) [span_132](start_span)Percabangan (Branching) untuk membuat ruang kerja terisolasi.[span_132](end_span) [span_133](start_span)Penggabungan (Merging) untuk menggabungkan kode paralel.[span_133](end_span) 3. [span_134](start_span)Setup Awal Git: git config --global user.name.[span_134](end_span) 4. [span_135](start_span)Workflow Dasar: Inisialisasi (git init).[span_135](end_span) [span_136](start_span)Mengecek status (git status).[span_136](end_span) [span_137](start_span)Stage (git add .).[span_137](end_span) [span_138](start_span)Commit (git commit -m ''pesan'').[span_138](end_span) [span_139](start_span)Melihat riwayat (git log).[span_139](end_span) 5. [span_140](start_span)Branching dan Merging: Membuat branch (git checkout -b ''nama'').[span_140](end_span) [span_141](start_span)Menggabungkan (git merge ''nama'').[span_141](end_span) 6. [span_142](start_span)Cloud/GitHub: Menyambungkan (git remote add), Push (git push), Clone (git clone), dan Pull (git pull).[span_142](end_span) 7. [span_143](start_span)Gitignore: Mengabaikan file log/password.[span_143](end_span) [span_144](start_span)Rebase vs Merge.[span_144](end_span) [span_145](start_span)Video ini sangat praktikal dan mensimulasikan pekerjaan Software Engineer sebenarnya, berkolaborasi melalui Pull Request di GitHub.[span_145](end_span)', 'https://www.youtube.com/live/KGSfUgaiVNI', 1),
('mat-w3-2', 'md-web-3', 'Video 5: TUTORIAL GIT DASAR (BAHASA INDONESIA)[span_146](start_span). 1. Pengertian & Latar Belakang: VCS merekam perubahan pada file dari waktu ke waktu.[span_146](end_span) [span_147](start_span)Ada tiga jenis VCS: Local, Centralized, dan Distributed (Git termasuk Distributed).[span_147](end_span) [span_148](start_span)Git dibuat oleh Linus Torvalds pada tahun 2005.[span_148](end_span) 2. [span_149](start_span)Workflow Git (The Three States): Working Directory (folder tempat mengetik kode), Staging Area (ruang tunggu file siap rekam), Repository (brankas utama).[span_149](end_span) [span_150](start_span)Alur Kerjanya: Working Directory -> git add -> Staging Area -> git commit -> Repository.[span_150](end_span) 4. [span_151](start_span)Praktek Penggunaan: git init, git status, git add, git commit.[span_151](end_span) [span_152](start_span)Melihat Perbedaan (git diff & git show).[span_152](end_span) 5. [span_153](start_span)Membatalkan Perubahan: Git diibaratkan seperti "mesin waktu".[span_153](end_span) Membatalkan di Working Directory (git restore). [span_154](start_span)Menggeser Mesin Waktu (git reset --hard).[span_154](end_span) Membatalkan dengan Aman (git revert). [span_155](start_span)Menggabungkan Perubahan (git commit --amend).[span_155](end_span) 6. [span_156](start_span)Fitur Tambahan: Gitignore, Git Blame (mencari tahu penulis sebaris kode), Git Alias (shortcut perintah).[span_156](end_span) [span_157](start_span)Kesimpulan: Video ini menanamkan pola pikir bahwa Git adalah manajer versi lokal, membiasakan pemula dengan terminal sebelum melangkah ke materi kolaborasi jarak jauh.[span_157](end_span)', 'https://youtu.be/fQbTeNX1mvM', 2),

-- Week 4
('mat-w4-1', 'md-web-4', 'Video 6: Membuat WEB PORTFOLIO dari Nol cocok untuk Pemula. 1. Tujuan: Membangun website portofolio yang minimalis, modern, dan responsif.[span_158](end_span) [span_159](start_span)Dibangun dengan HTML, CSS, dan JavaScript.[span_159](end_span) 2. [span_160](start_span)Struktur Section: Navbar (Navigasi), Hero Section dengan efek mengetik, Section Tentang (About), Section Proyek (Projects) dalam bentuk Grid, Contact & Footer.[span_160](end_span) [span_161](start_span)Tombol Scroll to Top untuk kembali ke atas.[span_161](end_span) 3. [span_162](start_span)Library & Tools: Live Server, Google Fonts, Getwaves.io, FontAwesome, Typed.js (untuk efek mengetik animasi teks), dan AOS (Animate On Scroll).[span_162](end_span) 4. Contoh Coding: HTML Dasar (Struktur Navbar). [span_163](start_span)CSS (Flexbox & Responsif menggunakan @media query).[span_163](end_span) [span_164](start_span)JavaScript digunakan untuk mendeteksi scroll layar (memunculkan/menghilangkan class ''scroll-aktif'').[span_164](end_span) [span_165](start_span)Script Typed.js dengan opsi strings: [''Diki'', ''Prayoga''].[span_165](end_span) [span_166](start_span)Kesimpulan: Video tutorial proyek terpandu ini sangat cocok untuk programmer pemula yang ingin memiliki portofolio lamaran kerja fungsional dan estetis.[span_166](end_span)', 'https://youtu.be/235DWjZudsI', 1),
('mat-w4-2', 'md-web-4', 'Video 7: Membuat WEB Landing Page Kedai Kopi. 1. Pengertian & Tujuan: Tutorial berbasis proyek untuk membangun landing page bisnis UMKM "Kenangan Senja" yang responsif.[span_167](end_span) 2. [span_168](start_span)Struktur Bagian: Navbar (sticky), Hero Section (gambar kopi dengan linear-gradient CTA), About Section (dibagi dua sisi), Menu Section (tata letak kartu Grid/Flexbox), Contact Section (Google Maps iframe), Footer.[span_168](end_span) 3. [span_169](start_span)Teknologi Pendukung: HTML5, CSS3, Vanilla JavaScript, Google Fonts, Feather Icons, Git & GitHub Actions (Niagahoster cPanel/FTP).[span_169](end_span) 4. [span_170](start_span)Konsep Utama: CSS Variables untuk menyimpan palet warna (--bg: #010101).[span_170](end_span) [span_171](start_span)Flexbox Layout (justify-content: space-between).[span_171](end_span) [span_172](start_span)Responsive Design dengan Media Query (max-width: 768px).[span_172](end_span) [span_173](start_span)JavaScript untuk memunculkan Hamburger Menu dengan manipulasi Class (navbarNav.classList.toggle(''active'')).[span_173](end_span) 5. [span_174](start_span)Autodeploy (CI/CD) ke Web Hosting: Mengotomatisasi peluncuran kode tanpa harus mengunggah file manual ke server cPanel setiap ada perubahan.[span_174](end_span) [span_175](start_span)Menggunakan FTP Account, GitHub Secrets, dan skrip YAML GitHub Actions.[span_175](end_span) [span_176](start_span)Hasilnya setiap melakukan git push ke GitHub, server otomatis memindahkan kode ke Web Hosting.[span_176](end_span) [span_177](start_span)Kesimpulan: Pengalaman siklus pengembangan penuh (End-to-End) dan praktik standar industri masa kini.[span_177](end_span)', 'https://youtu.be/MCVkMmYL-aY', 2);

